import{_ as t,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Cloudflare R2 Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/cloudflare-r2.md","filePath":"my/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"my/upload/cloudflare-r2.md"};function c(u,e,s,h,b,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare-r2-channel-ထည့်သွင်းခြင်း" tabindex="-1">Cloudflare R2 Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#cloudflare-r2-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;Cloudflare R2 Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="ဘယ်အချိန်မှာ-သုံးသင့်လဲ" tabindex="-1">ဘယ်အချိန်မှာ သုံးသင့်လဲ <a class="header-anchor" href="#ဘယ်အချိန်မှာ-သုံးသင့်လဲ" aria-label="Permalink to &quot;ဘယ်အချိန်မှာ သုံးသင့်လဲ&quot;">​</a></h2><p>Cloudflare R2 ကို ဒီအခြေအနေတွေမှာသုံးပါ:</p><ul><li>ImgBed site ကို Cloudflare ပေါ်မှာ deploy လုပ်ထားပြီး files တွေကို အဲ့ဒီ Cloudflare account ထဲက R2 bucket မှာသိမ်းချင်လျှင်။</li><li>S3 endpoint, access key, secret key ကို သီးခြား configure မလုပ်ချင်လျှင်။</li><li>reads/writes တွေကို Worker သို့မဟုတ် Pages R2 binding မှတစ်ဆင့် setup နည်းနည်းနဲ့သွားစေချင်လျှင်။</li></ul><p>အတိုချုပ်:</p><p>R2 channel ကို ImgBed admin panel ထဲမှာ manual မဖန်တီးပါ။ Cloudflare project ကို R2 bucket နဲ့အရင် bind လုပ်ရပြီး binding variable name က <code>img_r2</code> ဖြစ်ရပါမယ်။</p><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><ul><li>Cloudflare account။</li><li>ရှိပြီးသား R2 bucket။</li><li>ImgBed deploy လုပ်ထားတဲ့ Cloudflare project ကို manage လုပ်နိုင်တဲ့ permission။</li></ul><h2 id="cloudflare-မှာ-configure-လုပ်ပါ" tabindex="-1">Cloudflare မှာ Configure လုပ်ပါ <a class="header-anchor" href="#cloudflare-မှာ-configure-လုပ်ပါ" aria-label="Permalink to &quot;Cloudflare မှာ Configure လုပ်ပါ&quot;">​</a></h2><h3 id="_1-r2-bucket-ဖန်တီးပါ" tabindex="-1">1. R2 Bucket ဖန်တီးပါ <a class="header-anchor" href="#_1-r2-bucket-ဖန်တီးပါ" aria-label="Permalink to &quot;1. R2 Bucket ဖန်တီးပါ&quot;">​</a></h3><ol><li>Cloudflare Dashboard ထဲ log in ဝင်ပါ။</li><li><code>R2 Object Storage</code> ကိုဖွင့်ပါ။</li><li>Create bucket ကိုနှိပ်ပါ။</li><li>bucket name ရွေးပါ၊ ဥပမာ <code>imgbed</code>။</li></ol><p>uploaded files တွေကို ဒီ bucket ထဲမှာသိမ်းပါမယ်။</p><p><img src="'+t+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bucket-ကို-imgbed-project-နဲ့-bind-လုပ်ပါ" tabindex="-1">2. Bucket ကို ImgBed Project နဲ့ Bind လုပ်ပါ <a class="header-anchor" href="#_2-bucket-ကို-imgbed-project-နဲ့-bind-လုပ်ပါ" aria-label="Permalink to &quot;2. Bucket ကို ImgBed Project နဲ့ Bind လုပ်ပါ&quot;">​</a></h3><p>deployment type အလိုက် binding location ရွေးပါ:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>binding ထည့်တဲ့အခါ အရေးကြီးတဲ့ fields:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>ဖန်တီးထားတဲ့ bucket ကိုရွေးပါ။</td></tr></tbody></table><p>Variable name က တိတိကျကျ <code>img_r2</code> ဖြစ်ရပါမယ်။ R2 files upload/read/delete အားလုံးက ဒီ binding name ပေါ်မူတည်ပါတယ်။</p><h3 id="_3-project-ကို-redeploy-လုပ်ပါ" tabindex="-1">3. Project ကို Redeploy လုပ်ပါ <a class="header-anchor" href="#_3-project-ကို-redeploy-လုပ်ပါ" aria-label="Permalink to &quot;3. Project ကို Redeploy လုပ်ပါ&quot;">​</a></h3><p>binding save ပြီးနောက် ImgBed ကို redeploy လုပ်ပါ။ ဒါမှ Worker သို့မဟုတ် Pages runtime က <code>img_r2</code> ကို access လုပ်နိုင်ပါမယ်။</p><h2 id="imgbed-မှာ-ဘာမြင်ရမလဲ" tabindex="-1">ImgBed မှာ ဘာမြင်ရမလဲ <a class="header-anchor" href="#imgbed-မှာ-ဘာမြင်ရမလဲ" aria-label="Permalink to &quot;ImgBed မှာ ဘာမြင်ရမလဲ&quot;">​</a></h2><p>R2 binding ရရှိပြီးနောက် ဖွင့်ပါ:</p><ol><li>System Settings။</li><li>Upload Settings။</li><li><code>Cloudflare R2</code> channel။</li></ol><p>system က fixed channel တစ်ခုကို အလိုအလျောက်ဖန်တီးပါမယ်:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>ဒါက fixed binding channel ဖြစ်ပါတယ်။ ဖန်တီးဖို့ Add Channel ကိုနှိပ်စရာမလိုပါ၊ regular channel လို delete လုပ်လို့မရပါ။</p><h2 id="admin-panel-မှာ-ပြင်လို့ရတဲ့-fields" tabindex="-1">Admin Panel မှာ ပြင်လို့ရတဲ့ Fields <a class="header-anchor" href="#admin-panel-မှာ-ပြင်လို့ရတဲ့-fields" aria-label="Permalink to &quot;Admin Panel မှာ ပြင်လို့ရတဲ့ Fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>အသုံးပြုပုံ</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>R2 က upload selection ထဲပါမပါထိန်းချုပ်သည်။</td><td>Yes</td></tr><tr><td>Account ID</td><td>quota limits enabled ဖြစ်ပြီး official R2 usage query လုပ်ချင်တဲ့အခါသာသုံးသည်။</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Bucket name</td><td>quota limits enabled ဖြစ်ပြီး official R2 usage query လုပ်ချင်တဲ့အခါသာသုံးသည်။</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Quota limit</td><td>capacity အပေါ်မူတည်ပြီး R2 channel ကို upload selection ထဲပါစေမပါစေထိန်းချုပ်သည်။</td><td>No</td></tr><tr><td>Threshold</td><td>usage က သတ်မှတ်ထားတဲ့ percentage ရောက်ပြီးနောက် ဒီ channel ထဲရေးတာရပ်စေသည်။</td><td>Required when quota limits are enabled</td></tr></tbody></table><p>Account ID ကို Cloudflare dashboard ထဲက account information panel မှ copy လုပ်နိုင်ပါတယ်။ ImgBed က R2 quota usage ကို query/enforce လုပ်စေချင်မှသာဖြည့်ပါ။</p><p><img src="'+a+'" alt="Get the Account ID" loading="lazy"></p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Cloudflare မှာ R2 bucket ဖန်တီးပါ။</li><li>ImgBed project အတွက် Cloudflare settings ကိုဖွင့်ပါ။</li><li>R2 bucket binding ထည့်ပါ။</li><li><code>Variable name</code> ကို <code>img_r2</code> လို့ထားပါ။</li><li>ဖန်တီးထားတဲ့ R2 bucket ကိုရွေးပါ။</li><li>binding ကို save လုပ်ပြီး ImgBed ကို redeploy လုပ်ပါ။</li><li>ImgBed -&gt; System Settings -&gt; Upload Settings ကိုပြန်သွားပါ။</li><li><code>Cloudflare R2</code> channel ပေါ်လာပြီး enabled ဖြစ်လား confirm လုပ်ပါ။</li></ol><p>R2 ကို capacity အပေါ်မူတည်ပြီး upload selection ထဲပါစေချင်လျှင် quota limit ကို enable လုပ်ပြီး Account ID, bucket name, quota limit, threshold တို့ကိုဖြည့်ပြီး save လုပ်ပါ။</p><p><img src="'+d+'" alt="Configure quota limits" loading="lazy"></p><h2 id="စစ်ဆေးနည်း" tabindex="-1">စစ်ဆေးနည်း <a class="header-anchor" href="#စစ်ဆေးနည်း" aria-label="Permalink to &quot;စစ်ဆေးနည်း&quot;">​</a></h2><ul><li>fixed <code>Cloudflare R2</code> channel က Upload Settings မှာပေါ်လာရပါမယ်။</li><li>channel card မှာ enabled ဖြစ်ကြောင်းပြရပါမယ်။</li><li>test file သေးသေးတစ်ခု upload အောင်မြင်ပြီး returned link ဖွင့်လို့ရရပါမယ်။</li><li>file ဖွင့်တဲ့အခါ <code>R2 database binding is not configured</code> ပြရင် runtime က <code>img_r2</code> binding မရထားပါ။ Cloudflare မှာ binding name စစ်ပြီး project ကို redeploy လုပ်ပါ။</li></ul>',37)])])}const k=l(n,[["render",c]]);export{f as __pageData,k as default};
